  // 정원 10단계 업데이트 팝업
  garden_stage_1_title: { ko: "씨앗이 뿌려졌어요!",          de: "Ein Samen wurde gesät!", en: "Seed planted! 🌱", fr: "La graine est plantée ! 🌱" },
  garden_stage_1_desc: { ko: "겨자씨 한 알이 땅에 심겨졌어요.\n말씀이 마음 깊이 뿌리내리기 시작해요.", de: "Ein Senfkorn wurde in die Erde gelegt.\nGottes Wort beginnt, Wurzeln zu schlagen.", en: "A new journey begins with a tiny seed.", fr: "Un nouveau chemin commence avec une petite graine." },
  garden_stage_2_title: { ko: "새싹이 돋아났어요!",          de: "Ein Sprössling wächst!", en: "Sprout appears! 🌿", fr: "Une pousse apparaît ! 🌿" },
  garden_stage_2_desc: { ko: "작은 싹이 흙을 뚫고 올라왔어요.\n하나님 앞에 날마다 나아오고 있어요.", de: "Ein kleines Grün durchbricht die Erde.\nSie kommen täglich zu Gott.", en: "Your dedication is showing — a sprout appears!", fr: "Votre fidélité se voit — une pousse apparaît !" },
  garden_stage_3_title: { ko: "묘목이 자라고 있어요!",       de: "Der Setzling wächst!", en: "Seedling grows! 🌲", fr: "Le jeune arbre grandit ! 🌲" },
  garden_stage_3_desc: { ko: "뿌리가 단단히 내리고 줄기가 세워졌어요.\n말씀이 삶에 스며들고 있어요.", de: "Die Wurzeln greifen tief, der Stamm steht fest.\nGottes Wort durchdringt Ihr Leben.", en: "Growing day by day with God's Word.", fr: "Il grandit jour après jour avec la Parole de Dieu." },
  garden_stage_4_title: { ko: "가지가 뻗어나갔어요!",        de: "Äste breiten sich aus!", en: "Branches spread! 🌳", fr: "Les branches s’étendent ! 🌳" },
  garden_stage_4_desc: { ko: "가지가 사방으로 뻗어나가고 있어요.\n믿음이 삶의 구석구석에 닿고 있어요.", de: "Die Äste strecken sich in alle Richtungen.\nIhr Glaube berührt jeden Bereich Ihres Lebens.", en: "Your faith branches spread wide.", fr: "Les branches de votre foi s’étendent." },
  garden_stage_5_title: { ko: "나무가 무럭무럭 자라요!",     de: "Der Baum wächst kräftig!", en: "Getting stronger! 🌴", fr: "Il devient plus fort ! 🌴" },
  garden_stage_5_desc: { ko: "든든한 나무로 자라고 있어요.\n폭풍 속에서도 흔들리지 않아요.", de: "Ein starker Baum entsteht.\nAuch im Sturm bleibt er stehen.", en: "Deeply rooted, standing firm.", fr: "Bien enraciné, il tient ferme." },
  garden_stage_6_title: { ko: "잎이 풍성해졌어요!",          de: "Reichlich Blätter!", en: "Leaves unfold! 🍃", fr: "Les feuilles se déploient ! 🍃" },
  garden_stage_6_desc: { ko: "무성한 잎으로 그늘을 만들고 있어요.\n당신의 신앙이 주변을 덮기 시작해요.", de: "Üppiges Laub spendet Schatten.\nIhr Glaube beginnt, andere zu umhüllen.", en: "Beautiful leaves of faith unfold.", fr: "De belles feuilles de foi apparaissent." },
  garden_stage_7_title: { ko: "열매를 맺기 시작해요!",       de: "Früchte beginnen zu wachsen!", en: "Blooming! 🌺", fr: "Ça fleurit ! 🌺" },
  garden_stage_7_desc: { ko: "드디어 열매가 맺히기 시작했어요!\n말씀이 삶의 열매로 나타나고 있어요.", de: "Endlich zeigen sich die ersten Früchte!\nGottes Wort trägt Frucht in Ihrem Leben.", en: "Your garden of faith is blooming.", fr: "Votre jardin de foi est en fleurs." },
  garden_stage_8_title: { ko: "새들이 날아왔어요!",          de: "Vögel kommen!", en: "Bearing fruit! 🍎", fr: "Il porte du fruit ! 🍎" },
  garden_stage_8_desc: { ko: "새들이 날아와 가지에 깃들었어요.\n당신의 정원이 생명으로 가득해요.", de: "Vögel fliegen herbei und nisten in den Ästen.\nIhr Garten ist voller Leben.", en: "The fruit of the Spirit is forming.", fr: "Le fruit de l’Esprit se forme." },
  garden_stage_9_title: { ko: "정원이 거의 완성돼요!",       de: "Der Garten ist fast fertig!", en: "Garden shines! ✨", fr: "Le jardin rayonne ! ✨" },
  garden_stage_9_desc: { ko: "아름다운 정원이 거의 완성됐어요.\n100일을 향해 달려가고 있어요!", de: "Ein wunderschöner Garten entsteht.\n100 Tage sind fast erreicht!", en: "Your garden radiates God's glory.", fr: "Votre jardin reflète la gloire de Dieu." },
  garden_stage_10_title: { ko: "풍성한 정원 완성!",           de: "Üppiger Garten vollendet!", en: "Garden complete! 🏆", fr: "Jardin complet ! 🏆" },
  garden_stage_10_desc: { ko: "100일의 여정을 거의 마쳤어요!\n곧 성령의 열매 배지를 받게 돼요.", de: "Die 100-Tage-Reise ist fast abgeschlossen!\nBald erhalten Sie die Frucht des Geistes.", en: "Congratulations! Time for a spirit fruit!", fr: "Félicitations ! C’est le moment du fruit de l’Esprit !" },

